import { sanitizeFilename } from './solution';
test('sanitizeFilename basic', () => {
  expect(sanitizeFilename('hello world.txt')).toBe('hello world.txt');
  expect(sanitizeFilename('CON: <test>.txt')).toBe('CON_test.txt');
  expect(sanitizeFilename('file?name*.ext')).toBe('file_name.ext');
  expect(sanitizeFilename('  .hidden.  ')).toBe('hidden');
  expect(sanitizeFilename('a<b>c:d"e/f\\g|h?i*j')).toBe('a_b_c_d_e_f_g_h_i_j');
});

import { getDirSize } from './solution';
import * as fs from 'fs/promises';
import * as path from 'path';
import * as os from 'os';

test('getDirSize non-exist', async () => {
  expect(await getDirSize('/non/existent/path')).toBe(-1);
});

test('getDirSize empty dir', async () => {
  const dir = path.join(os.tmpdir(), 'easysize_test_' + Date.now());
  await fs.mkdir(dir);
  try {
    expect(await getDirSize(dir)).toBe(0);
  } finally {
    await fs.rm(dir, { recursive: true, force: true });
  }
});

test('getDirSize with files', async () => {
  const dir = path.join(os.tmpdir(), 'easysize_test2_' + Date.now());
  await fs.mkdir(dir);
  try {
    await fs.writeFile(path.join(dir, 'a.txt'), 'hello');
    await fs.writeFile(path.join(dir, 'b.txt'), 'world!');
    const size = await getDirSize(dir);
    expect(size).toBe(5 + 6);
  } finally {
    await fs.rm(dir, { recursive: true, force: true });
  }
});

import { LRUCache } from './solution';

test('LRUCache basic', () => {
  const cache = new LRUCache<string, number>(2);
  cache.put('a', 1);
  cache.put('b', 2);
  expect(cache.get('a')).toBe(1);
  cache.put('c', 3); // 淘汰 'b'
  expect(cache.get('b')).toBeUndefined();
  expect(cache.get('a')).toBe(1);
  expect(cache.get('c')).toBe(3);
});

test('LRUCache update', () => {
  const cache = new LRUCache<number, string>(2);
  cache.put(1, 'one');
  cache.put(1, 'ONE'); // 更新
  expect(cache.get(1)).toBe('ONE');
  expect(cache.size).toBe(1);
});

test('LRUCache keys order', () => {
  const cache = new LRUCache<string, number>(3);
  cache.put('a', 1);
  cache.put('b', 2);
  cache.put('c', 3);
  cache.get('a'); // 移到末尾
  expect(cache.keys()).toEqual(['b', 'c', 'a']);
});

test('LRUCache capacity 1', () => {
  const cache = new LRUCache<number, number>(1);
  cache.put(1, 10);
  cache.put(2, 20);
  expect(cache.get(1)).toBeUndefined();
  expect(cache.get(2)).toBe(20);
});

import { validateJSON, JSONSchema } from './solution';

test('validateJSON type check', () => {
  const schema: JSONSchema = { type: 'string' };
  expect(validateJSON(schema, 'hello').valid).toBe(true);
  expect(validateJSON(schema, 42).valid).toBe(false);
});

test('validateJSON object with required', () => {
  const schema: JSONSchema = {
    type: 'object',
    required: ['name', 'age'],
    properties: {
      name: { type: 'string' },
      age: { type: 'number', minimum: 0 }
    }
  };
  expect(validateJSON(schema, { name: 'Alice', age: 25 }).valid).toBe(true);
  expect(validateJSON(schema, { name: 'Bob' }).valid).toBe(false);
  expect(validateJSON(schema, { name: 'Eve', age: -1 }).valid).toBe(false);
});

test('validateJSON nested object', () => {
  const schema: JSONSchema = {
    type: 'object',
    properties: {
      user: {
        type: 'object',
        properties: {
          name: { type: 'string', minLength: 2 },
          email: { type: 'string' }
        }
      }
    }
  };
  expect(validateJSON(schema, { user: { name: 'Al', email: 'a@b.com' } }).valid).toBe(false);
  const r = validateJSON(schema, { user: { name: 'Alice', email: 'a@b.com' } });
  expect(r.valid).toBe(true);
  expect(r.errors).toHaveLength(0);
});

test('validateJSON array with items', () => {
  const schema: JSONSchema = { type: 'array', items: { type: 'number', minimum: 0 } };
  expect(validateJSON(schema, [1, 2, 3]).valid).toBe(true);
  expect(validateJSON(schema, [1, -2, 3]).valid).toBe(false);
});

test('validateJSON enum', () => {
  const schema: JSONSchema = { enum: ['red', 'green', 'blue'] };
  expect(validateJSON(schema, 'red').valid).toBe(true);
  expect(validateJSON(schema, 'yellow').valid).toBe(false);
});

import { retry } from './solution';

test('retry success on first try', async () => {
  const fn = async () => 'result';
  const result = await retry(fn);
  expect(result).toBe('result');
});

test('retry success on second try', async () => {
  let calls = 0;
  const fn = async () => {
    calls++;
    if (calls === 1) throw new Error('fail');
    return 'ok';
  };
  const result = await retry(fn, { maxRetries: 3, delayMs: 10 });
  expect(result).toBe('ok');
  expect(calls).toBe(2);
});

test('retry exhausts retries', async () => {
  const fn = async () => { throw new Error('always fail'); };
  await expect(retry(fn, { maxRetries: 2, delayMs: 10 })).rejects.toThrow('always fail');
});

test('retry shouldRetry filter', async () => {
  const fn = async () => { throw new TypeError('bad type'); };
  await expect(
    retry(fn, {
      maxRetries: 3,
      delayMs: 10,
      shouldRetry: (err) => err.message !== 'bad type'
    })
  ).rejects.toThrow('bad type');
});

test('retry onRetry callback', async () => {
  const retries: number[] = [];
  let calls = 0;
  const fn = async () => {
    calls++;
    if (calls <= 2) throw new Error(`fail ${calls}`);
    return 'done';
  };
  const result = await retry(fn, {
    maxRetries: 3,
    delayMs: 10,
    onRetry: (err, attempt) => retries.push(attempt)
  });
  expect(result).toBe('done');
  expect(retries).toEqual([1, 2]);
});

import { parseSemver, compareSemver } from './solution';

test('parseSemver valid', () => {
  expect(parseSemver('1.2.3')).toEqual({ major: 1, minor: 2, patch: 3, prerelease: [], build: [] });
  expect(parseSemver('0.0.0')).toEqual({ major: 0, minor: 0, patch: 0, prerelease: [], build: [] });
  expect(parseSemver('2.0.0-alpha.1+build.123').prerelease).toEqual(['alpha', '1']);
});

test('parseSemver invalid', () => {
  expect(parseSemver('01.2.3')).toBeNull();
  expect(parseSemver('1.2')).toBeNull();
  expect(parseSemver('v1.2.3')).toBeNull();
  expect(parseSemver('1.2.3.4')).toBeNull();
  expect(parseSemver('abc')).toBeNull();
});

test('compareSemver basic', () => {
  expect(compareSemver('1.0.0', '2.0.0')).toBe(-1);
  expect(compareSemver('2.0.0', '1.0.0')).toBe(1);
  expect(compareSemver('1.2.3', '1.2.3')).toBe(0);
  expect(compareSemver('1.9.0', '1.10.0')).toBe(-1);
});

test('compareSemver prerelease', () => {
  expect(compareSemver('1.0.0-alpha', '1.0.0')).toBe(-1);
  expect(compareSemver('1.0.0-alpha', '1.0.0-beta')).toBe(-1);
  expect(compareSemver('1.0.0-alpha.2', '1.0.0-alpha.10')).toBe(-1);
});

test('compareSemver invalid input', () => {
  expect(compareSemver('invalid', '1.0.0')).toBeNull();
  expect(compareSemver('1.0.0', 'x.y.z')).toBeNull();
});

import { deepMerge } from './solution';

test('deepMerge basic', () => {
  const result = deepMerge({ a: 1 }, { b: 2 });
  expect(result).toEqual({ a: 1, b: 2 });
});

test('deepMerge nested', () => {
  const result = deepMerge(
    { a: { x: 1, y: 2 }, b: 3 },
    { a: { y: 20, z: 30 } }
  );
  expect(result).toEqual({ a: { x: 1, y: 20, z: 30 }, b: 3 });
});

test('deepMerge array override', () => {
  const result = deepMerge({ arr: [1, 2] }, { arr: [3] });
  expect(result).toEqual({ arr: [3] });
});

test('deepMerge immutability', () => {
  const target = { a: { x: 1 } };
  const source = { a: { y: 2 } };
  const result = deepMerge(target, source);
  expect(target.a).toEqual({ x: 1 });
  expect(source.a).toEqual({ y: 2 });
  expect(result).toEqual({ a: { x: 1, y: 2 } });
  expect(result).not.toBe(target);
  expect(result.a).not.toBe(target.a);
});

test('deepMerge multiple sources', () => {
  const result = deepMerge({ a: 1 }, { b: 2 }, { c: 3 });
  expect(result).toEqual({ a: 1, b: 2, c: 3 });
});

import { TypedEmitter } from './solution';

type MyEvents = {
  data: [string, number];
  error: [Error];
  close: [];
};

test('TypedEmitter on/emit', () => {
  const emitter = new TypedEmitter<MyEvents>();
  const received: [string, number][] = [];
  emitter.on('data', (msg, code) => received.push([msg, code]));
  emitter.emit('data', 'hello', 200);
  emitter.emit('data', 'world', 201);
  expect(received).toEqual([['hello', 200], ['world', 201]]);
});

test('TypedEmitter once', () => {
  const emitter = new TypedEmitter<MyEvents>();
  let count = 0;
  emitter.once('data', () => { count++; });
  emitter.emit('data', 'a', 1);
  emitter.emit('data', 'b', 2);
  expect(count).toBe(1);
});

test('TypedEmitter off', () => {
  const emitter = new TypedEmitter<MyEvents>();
  let count = 0;
  const fn = () => { count++; };
  emitter.on('data', fn);
  emitter.emit('data', 'a', 1);
  emitter.off('data', fn);
  emitter.emit('data', 'b', 2);
  expect(count).toBe(1);
});

test('TypedEmitter safe remove during emit', () => {
  const emitter = new TypedEmitter<MyEvents>();
  let count = 0;
  const fn1 = () => { emitter.off('data', fn2); count++; };
  const fn2 = () => { count++; };
  emitter.on('data', fn1);
  emitter.on('data', fn2);
  emitter.emit('data', 'test', 0);
  expect(count).toBe(2);
});

test('TypedEmitter listenerCount', () => {
  const emitter = new TypedEmitter<MyEvents>();
  expect(emitter.listenerCount('data')).toBe(0);
  emitter.on('data', () => {});
  emitter.on('data', () => {});
  expect(emitter.listenerCount('data')).toBe(2);
  emitter.removeAllListeners('data');
  expect(emitter.listenerCount('data')).toBe(0);
});

import { parseCSV } from './solution';

test('parseCSV simple', () => {
  const result = parseCSV('a,b,c\n1,2,3');
  expect(result).toEqual([['a', 'b', 'c'], ['1', '2', '3']]);
});

test('parseCSV quoted fields', () => {
  const result = parseCSV('"hello, world",123\n"a","b"');
  expect(result).toEqual([['hello, world', '123'], ['a', 'b']]);
});

test('parseCSV escaped quotes', () => {
  const result = parseCSV('"She said ""hi""",123');
  expect(result).toEqual([['She said "hi"', '123']]);
});

test('parseCSV multiline field', () => {
  const result = parseCSV('a,b\n"line1\nline2",c');
  expect(result).toEqual([['a', 'b'], ['line1\nline2', 'c']]);
});

test('parseCSV hasHeader', () => {
  const result = parseCSV('Name,Age\nAlice,30\nBob,25', { hasHeader: true });
  expect(result).toEqual([['Alice', '30'], ['Bob', '25']]);
});

test('parseCSV empty fields', () => {
  const result = parseCSV('a,,c\n,,');
  expect(result).toEqual([['a', '', 'c'], ['', '', '']]);
});

test('parseCSV custom delimiter', () => {
  const result = parseCSV('a|b|c\n1|2|3', { delimiter: '|' });
  expect(result).toEqual([['a', 'b', 'c'], ['1', '2', '3']]);
});

import { WeightedRandom } from './solution';

test('WeightedRandom select returns valid item', () => {
  const wr = new WeightedRandom([
    { item: 'a', weight: 1 },
    { item: 'b', weight: 2 },
  ]);
  const selected = wr.select();
  expect(['a', 'b']).toContain(selected);
});

test('WeightedRandom zero weight never selected', () => {
  const wr = new WeightedRandom([
    { item: 'always', weight: 1 },
    { item: 'never', weight: 0 },
  ]);
  for (let i = 0; i < 100; i++) {
    expect(wr.select()).toBe('always');
  }
});

test('WeightedRandom distribution', () => {
  const wr = new WeightedRandom([
    { item: 'a', weight: 1 },
    { item: 'b', weight: 3 },
  ]);
  const dist = wr.getDistribution();
  expect(dist.find(d => d.item === 'a')!.probability).toBeCloseTo(0.25, 1);
  expect(dist.find(d => d.item === 'b')!.probability).toBeCloseTo(0.75, 1);
});

test('WeightedRandom selectN', () => {
  const wr = new WeightedRandom([{ item: 'x', weight: 1 }]);
  const results = wr.selectN(5);
  expect(results).toHaveLength(5);
  expect(results.every(r => r === 'x')).toBe(true);
});

test('WeightedRandom empty input throws', () => {
  expect(() => new WeightedRandom([])).toThrow();
});

test('WeightedRandom negative weight throws', () => {
  expect(() => new WeightedRandom([{ item: 'x', weight: -1 }])).toThrow();
});
